from collections import defaultdict, deque

def solve(deps: dict[str, list[str]]) -> list[list[str]]:
    # Build full node set
    nodes = set(deps.keys())
    for prereqs in deps.values():
        nodes.update(prereqs)

    # adj: prerequisite -> tasks that depend on it
    # indegree: number of prerequisites for each task
    indegree = {n: 0 for n in nodes}
    adj = defaultdict(list)
    for task, prereqs in deps.items():
        for p in prereqs:
            adj[p].append(task)
            indegree[task] += 1

    layers = []
    current = sorted([n for n in nodes if indegree[n] == 0])
    processed = 0

    while current:
        layers.append(current)
        processed += len(current)
        next_layer = []
        for node in current:
            for nb in adj[node]:
                indegree[nb] -= 1
                if indegree[nb] == 0:
                    next_layer.append(nb)
        current = sorted(next_layer)

    if processed != len(nodes):
        return []

    return layers
