def solve(capacity: int, ops: list[str]) -> list[int]:
    cache = OrderedDict()
    results = []
    for op in ops:
        parts = op.split()
        if parts[0] == "get":
            key = parts[1]
            if capacity == 0 or key not in cache:
                results.append(-1)
            else:
                cache.move_to_end(key)
                results.append(cache[key])
        elif parts[0] == "put":
            key = parts[1]
            value = int(parts[2])
            if capacity == 0:
                continue
            if key in cache:
                cache.move_to_end(key)
                cache[key] = value
            else:
                if len(cache) >= capacity:
                    cache.popitem(last=False)
                cache[key] = value
    return results
