from bisect import insort, bisect_left

def solve(nums: list[int], k: int) -> list[float]:
    if k <= 0 or k > len(nums):
        return []

    window = sorted(nums[:k])
    res = []

    def median(w: list[int]) -> float:
        if k % 2:
            return float(w[k // 2])
        return (w[k // 2 - 1] + w[k // 2]) / 2.0

    res.append(median(window))

    for i in range(k, len(nums)):
        old = nums[i - k]
        window.pop(bisect_left(window, old))
        insort(window, nums[i])
        res.append(median(window))

    return res
