def solve(deps: dict[str, list[str]], changed: list[str]) -> list[str]:
    rev = defaultdict(list)
    nodes = set()
    for pkg, dlist in deps.items():
        nodes.add(pkg)
        for d in dlist:
            nodes.add(d)
            rev[d].append(pkg)

    result = set()
    q = deque(changed)
    for c in changed:
        result.add(c)

    while q:
        cur = q.popleft()
        for parent in rev.get(cur, []):
            if parent not in result:
                result.add(parent)
                q.append(parent)

    return sorted(result)
